css:
.loader {
  perspective: 700px;
  background: #ef4444;
  padding: 12px 22px;
  border-radius: 10px;
  display: inline-flex;
  gap: 1px;
}
.loader > span {
  font-size: 42px;
  line-height: 1;
  font-family: "Franklin Gothic Medium", Arial, sans-serif;
  display: inline-block;
  animation: letterFlip 2.6s infinite linear;
  transform-origin: 0 70%;
  transform-style: preserve-3d;
  color: #111111;
}
.loader > span:nth-child(even) { color: #ffffff; }
.loader > span:nth-child(2) { animation-delay: .3s; }
.loader > span:nth-child(3) { animation-delay: .6s; }
.loader > span:nth-child(4) { animation-delay: .9s; }
.loader > span:nth-child(5) { animation-delay: 1.2s; }
.loader > span:nth-child(6) { animation-delay: 1.5s; }
.loader > span:nth-child(7) { animation-delay: 1.8s; }
@keyframes letterFlip { 35%,100% { transform: rotateZ(360deg); } }
